// ====================== MODAL ======================

function openFindSeatModal() {

    document.getElementById("findSeatModal").style.display = "flex";

    loadDropdowns();

    clearModalMessage();

}

function closeFindSeatModal() {

    document.getElementById("findSeatModal").style.display = "none";

    clearModalMessage();

}

// ====================== MODAL MESSAGE (BOTTOM ERROR/NOTE) ======================

function setModalMessage(message, type = "error") {

    const box = document.getElementById("modal-message");

    box.innerHTML = message;

    box.style.display = "block";

    box.style.padding = "10px";

    box.style.marginTop = "10px";

    box.style.borderRadius = "8px";

    box.style.fontSize = "13px";

    if (type === "error") {

        box.style.background = "#fee2e2";

        box.style.color = "#991b1b";

        box.style.border = "1px solid #fca5a5";

    } else {

        box.style.background = "#e0f2fe";

        box.style.color = "#075985";

        box.style.border = "1px solid #7dd3fc";

    }

}

function clearModalMessage() {

    const box = document.getElementById("modal-message");

    box.style.display = "none";

    box.innerHTML = "";

}

// ====================== LOAD DROPDOWNS ======================

function loadDropdowns() {

    const students = generateSeatData(globalStudents);

    const courseSelect = document.getElementById("findCourse");

    const collegeSelect = document.getElementById("findCollege");

    courseSelect.innerHTML = `<option value="">Select Course</option>`;
    collegeSelect.innerHTML = `<option value="">Select College</option>`;

    const courses = [...new Set(students.map(s => s.course).filter(Boolean))].sort();
    const colleges = [...new Set(students.map(s => s.college).filter(Boolean))].sort();

    courses.forEach(c => {
        courseSelect.innerHTML += `<option value="${c}">${c}</option>`;
    });

    colleges.forEach(c => {
        collegeSelect.innerHTML += `<option value="${c}">${c}</option>`;
    });

}

// ====================== FIND SEAT ======================

function findMySeat() {

    const name = document.getElementById("findName").value.trim().toLowerCase();
    const course = document.getElementById("findCourse").value.trim().toLowerCase();
    const college = document.getElementById("findCollege").value.trim().toLowerCase();

    if (!name || !course || !college) {

        setModalMessage("Please complete all fields.", "error");

        return;

    }

    const students = generateSeatData(globalStudents);

    const found = students.find(s => {

        return (
            (s.name || "").toLowerCase().includes(name) &&
            (s.course || "").toLowerCase() === course &&
            (s.college || "").toLowerCase() === college
        );

    });

    if (!found) {

        setModalMessage(
            "Student not found. Please double-check:<br>" +
            "• Name spelling<br>" +
            "• Course selection<br>" +
            "• College selection<br><br>" +
            "Note: Ensure your graduation details are correct in the system.",
            "error"
        );

        return;

    }

    clearModalMessage();

    showInfo(found);

    closeFindSeatModal();

    document.querySelectorAll(".seat").forEach(s => s.classList.remove("selected"));

    document.querySelectorAll(".seat").forEach(seat => {

        const seatCode = seat.querySelector(".seat-code")?.innerText?.trim();

        if (seatCode === found.seat) {

            seat.classList.add("selected");

            seat.scrollIntoView({
                behavior: "smooth",
                block: "center",
                inline: "center"
            });

        }

    });

    window.scrollTo({ top: 0, behavior: "smooth" });

}
